CREATE TABLE "altsayfa" (
  "id" INTEGER NOT NULL,
  "urunadi" TEXT DEFAULT NULL,
  "seo" TEXT NOT NULL,
  "aciklama" TEXT NOT NULL,
  "tarih" TEXT NOT NULL,
  "resimbuyuk" TEXT NOT NULL,
  "resimkucuk" VARCHAR NOT NULL,
  "kod" VARCHAR NOT NULL,
  "meta" TEXT NOT NULL,
  "keyword" TEXT NOT NULL
);
CREATE TABLE "ayarlar" (
  "id" INTEGER NOT NULL,
  "siteadi" TEXT DEFAULT NULL,
  "siteadresi" TEXT DEFAULT NULL,
  "slogan" TEXT DEFAULT NULL,
  "title" TEXT DEFAULT NULL,
  "meta" TEXT DEFAULT NULL,
  "footer" TEXT DEFAULT NULL,
  "facebook" TEXT DEFAULT NULL,
  "twitter" TEXT DEFAULT NULL,
  "rss" TEXT DEFAULT NULL,
  "google" TEXT DEFAULT NULL,
  "mail" TEXT DEFAULT NULL,
  "firmaadresi" TEXT DEFAULT NULL,
  "telefon" TEXT DEFAULT NULL,
  "gsm" TEXT DEFAULT NULL,
  "yetkili" TEXT DEFAULT NULL,
  "keyword" TEXT DEFAULT NULL,
  "analiz" TEXT NOT NULL,
  "anasayfa" VARCHAR NOT NULL,
  "hakkimizda" VARCHAR NOT NULL,
  "koleksiyon" VARCHAR NOT NULL,
  "magazalar" VARCHAR NOT NULL,
  "haberler" VARCHAR NOT NULL,
  "iletisim" VARCHAR NOT NULL,
  "ayarno" INTEGER NOT NULL DEFAULT 1
);
CREATE TABLE "counter_ips" (
  "ip" VARCHAR   NOT NULL,
