  "month_id" BIGINT NOT NULL,
  "month_value" BIGINT NOT NULL,
  "year_id" BIGINT NOT NULL,
  "year_value" BIGINT NOT NULL,
  "all_value" BIGINT NOT NULL,
  "record_date" TIMESTAMP NOT NULL,
  "record_value" BIGINT NOT NULL
);
